replace_validation_record_in_array.inputs:
@union(
    union(
        take(
          variables('AmountValidationArray'),
          first(body('Filter_Validation_Array'))?['index']
        ),
        createArray(
            outputs('validation_record_property_updates')
        )
    ),
    skip(
        variables('AmountValidationArray'),
        add(
          first(body('Filter_Validation_Array'))?['index'], 
          1
        )
    )
)

